showRoutes = <E extends Env>(hono: Hono<E>, opts?: ShowRoutesOptions): void => {
  const colorEnabled = opts?.colorize ?? getColorEnabled()
  const routeData: Record<string, RouteData[]> = {}
  let maxMethodLength = 0
  let maxPathLength = 0

  inspectRoutes(hono)
    .filter(({ isMiddleware }) => opts?.verbose || !isMiddleware)
    .map((route) => {
      const key = `${route.method}-${route.path}`
      ;(routeData[key] ||= []).push(route)
      if (routeData[key].length > 1) {
        return
      }
      maxMethodLength = Math.max(maxMethodLength, route.method.length)
      maxPathLength = Math.max(maxPathLength, route.path.length)
      return { method: route.method, path: route.path, routes: routeData[key] }
    })
    .forEach((data) => {
      if (!data) {
        return
      }
      const { method, path, routes } = data

      const methodStr = colorEnabled ? `\x1b[32m${method}\x1b[0m` : method
      console.log(`${methodStr} ${' '.repeat(maxMethodLength - method.length)} ${path}`)

      if (!opts?.verbose) {
        return
      }

      routes.forEach(({ name }) => {
        console.log(`${' '.repeat(maxMethodLength + 3)} ${name}`)
      })
    })
}

hasUnsafeStyleValue = (value: string): boolean => {
  if (!unsafeStyleValueCharRe.test(value)) {
    return false
  }

  let quote = 0
  const blockStack: number[] = []
  for (let i = 0, len = value.length; i < len; i++) {
    const c = value.charCodeAt(i)
    if (c === 0x5c) {
      if (i === len - 1) {
        return true
      }
      i++
    } else if (quote !== 0) {
      if (c === 0x0a || c === 0x0c || c === 0x0d) {
        return true
      }
      if (c === quote) {
        quote = 0
      }
    } else if (c === 0x2f && value.charCodeAt(i + 1) === 0x2a) {
      const end = value.indexOf('*/', i + 2)
      if (end === -1) {
        return true
      }
      i = end + 1
    } else if (c === 0x22 || c === 0x27) {
      quote = c
    } else if (c === 0x28) {
      blockStack.push(0x29)
    } else if (c === 0x5b) {
      blockStack.push(0x5d)
    } else if (c === 0x7b || c === 0x7d) {
      return true
    } else if (c === 0x29 || c === 0x5d) {
      if (blockStack[blockStack.length - 1] !== c) {
        return true
      }
      blockStack.pop()
    } else if (c === 0x3b && blockStack.length === 0) {
      return true
    }
  }
  return quote !== 0 || blockStack.length !== 0
}

add(method: string, path: string, handler: T) {
  if (!this.#matchers[method]) {
    const all = this.#matchers[METHOD_NAME_ALL] as Matcher<T>
    const staticMap = {} as StaticMap<T>
    for (const key in all[2]) {
      staticMap[key] = [all[2][key][0].slice(), emptyParam] as Result<T>
    }
    this.#matchers[method] = [
      all[0],
      all[1].map((list) => (Array.isArray(list) ? list.slice() : 0)) as HandlerData<T>[],
      staticMap,
    ]
  }

  if (path === '/*' || path === '*') {
    const handlerData: [T, ParamIndexMap] = [handler, {}]
    if (method === METHOD_NAME_ALL) {
      for (const m in this.#matchers) {
        this.#addWildcard(m, handlerData)
      }
    } else {
      this.#addWildcard(method, handlerData)
    }
    return
  }

  const data = this.#relocateMap[path]
  if (!data) {
    throw new Error(`Path ${path} is not registered`)
  }
  for (const [indexes, map] of data) {
    if (method === METHOD_NAME_ALL) {
      for (const m in this.#matchers) {
        this.#addPath(m, path, handler, indexes, map)
      }
    } else {
      this.#addPath(method, path, handler, indexes, map)
    }
  }
}

function validator<
  Schema extends StandardSchemaV1,
  Target extends keyof ValidationTargets,
  E extends Env,
  P extends string,
  In = StandardSchemaV1.InferInput<Schema>,
  Out = StandardSchemaV1.InferOutput<Schema>,
  I extends Input = {
    in: HasUndefined<In> extends true
      ? {
          [K in Target]?: In extends ValidationTargets[K]
            ? In
            : { [K2 in keyof In]?: ValidationTargets[K][K2] };
        }
      : {
          [K in Target]: In extends ValidationTargets[K]
            ? In
            : { [K2 in keyof In]: ValidationTargets[K][K2] };
        };
    out: { [K in Target]: Out };
  },
  V extends I = I,
>(
  target: Target,
  schema: Schema,
  hook?: Hook<StandardSchemaV1.InferOutput<Schema>, E, P, Target>,
  options?: ResolverReturnType["options"],
): MiddlewareHandler<E, P, V> {
  const middleware = sValidator(target, schema, hook);

  // @ts-expect-error not typed well
  return Object.assign(middleware, {
    [uniqueSymbol]: {
      target,
      ...resolver(schema, options),
      options,
    },
  });
}
